18	  return BASE_PREMIUM[item.type] ?? 0;
19	}
20	
21	function countByType(items: any[]): Record<string, number> {
22	  const counts: Record<string, number> = {};
23	  for (const item of items) {
24	    counts[item.type] = (counts[item.type] ?? 0) + 1;
25	  }
26	  return counts;
27	}
28	
29	function calculateBasePremium(typeCounts: Record<string, number>): number {
30	  let total = 0;
31	  for (const [type, count] of Object.entries(typeCounts)) {
32	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
33	      total += BLOCK_PREMIUM;
34	    } else {
35	      total += count * (BASE_PREMIUM[type] ?? 0);
36	    }
37	  }
38	  return total;
39	}
40	
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const ENCHANTMENT_THRESHOLD = 5;
44	
45	function calculateItemSurcharges(items: any[]): number {
46	  let total = 0;
47	  for (const item of items) {
48	    const base = getItemBasePremium(item);
49	    if (item.cursed) {
50	      total += base * CURSED_SURCHARGE_RATE;
51	    }
52	    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
53	      total += base * ENCHANTMENT_SURCHARGE_RATE;
54	    }
55	  }
56	  return total;
57	}
58	
59	const LOYALTY_DISCOUNT_RATE = 0.2;
60	const LOYALTY_THRESHOLD_YEARS = 2;
61	
62	function calculateQuotePremium(items: any[], customer: any): number {
63	  const typeCounts = countByType(items);
64	  const basePremium = calculateBasePremium(typeCounts);
65	  const itemSurcharges = calculateItemSurcharges(items);
66	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
67	  const loyaltyDiscount = (customer.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
68	    ? basePremium * LOYALTY_DISCOUNT_RATE
69	    : 0;
70	  return Math.ceil(basePremium + itemSurcharges - loyaltyDiscount + firstInsurance + PROCESSING_FEE);
71	}
72	
73	export function processScenario(scenario: any): unknown {
74	  const results = scenario.steps.map((step: any) => ({
75	    premium: calculateQuotePremium(step.items, scenario.customer),
76	  }));
77	
78	  return { results };
79	}
